#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10,INF=0x3f3f3f3f;

struct Node{
    long long mx,add,mdf;
}t[N<<2];

int n,q,a[N];

void build(int cur,int l,int r){
    t[cur].add=0,t[cur].mdf=INF;
    if(l==r){
        t[cur].mx=a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur].mx=max(t[cur*2].mx,t[cur*2+1].mx);
}

void push_down(int cur,int l,int r){
    if(t[cur].mdf!=INF){
        t[cur*2]=t[cur*2+1]={t[cur].mdf,0,t[cur].mdf};
        t[cur].mdf=INF;
    }
    if(t[cur].add){
        t[cur*2]={t[cur*2].mx+t[cur].add,t[cur*2].add+t[cur].add,t[cur*2].mdf};
        t[cur*2+1]={t[cur*2+1].mx+t[cur].add,t[cur*2+1].add+t[cur].add,t[cur*2+1].mdf};
        t[cur].add=0;
    }
}

void modify(int cur,int l,int r,int x,int y,int k,int tp){
    if(x<=l && r<=y){
        if(tp==1)
            t[cur]={k,0,k};
        else
            t[cur]={t[cur].mx+k,t[cur].add+k,t[cur].mdf};
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k,tp);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k,tp);
    t[cur].mx=max(t[cur*2].mx,t[cur*2+1].mx);
}

long long query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur].mx;
    int mid=l+r>>1;
    push_down(cur,l,r);
    long long res=-1e18;
    if(x<=mid)
        res=max(res,query(cur*2,l,mid,x,y));
    if(y>mid)
        res=max(res,query(cur*2+1,mid+1,r,x,y));
    return res;
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    while(q--){
        int op,l,r,x;
        scanf("%d%d%d",&op,&l,&r);
        if(op<=2){
            scanf("%d",&x);
            modify(1,1,n,l,r,x,op);
        }else
            printf("%lld\n",query(1,1,n,l,r));
    }
    return 0;
}
